func solve(nums []int64) int64 {
    max_value := int64(0)

    memo := make(map[string]int64)

    var dfs func(int, int64, int64, int64, int64) int64
    dfs = func(index, a_xor, b_and, c_xor, mask int64) int64 {
        // If we have processed all numbers, return the sum
        if index == int64(len(nums)) {
            return a_xor + b_and + c_xor
        }

        // Check if we have already computed this state
        key := fmt.Sprintf("%d_%d_%d_%d_%d", index, a_xor, b_and, c_xor, mask)
        if val, found := memo[key]; found {
            return val
        }

        max_val := int64(0)

        // Assign to A
        new_a_xor := a_xor ^ nums[index]
        new_val := dfs(index+1, new_a_xor, b_and, c_xor, mask)
        if new_val > max_val {
            max_val = new_val
        }

        // Assign to B
        new_b_and := b_and & nums[index]
        new_val = dfs(index+1, a_xor, new_b_and, c_xor, mask)
        if new_val > max_val {
            max_val = new_val
        }

        // Assign to C
        new_c_xor := c_xor ^ nums[index]
        new_val = dfs(index+1, a_xor, b_and, new_c_xor, mask)
        if new_val > max_val {
            max_val = new_val
        }

        // Store the result in memoization table
        memo[key] = max_val
        return max_val
    }

    result := dfs(0, 0, 0, 0, 0)
    return result
}
